// This file is part of the universal numbers project, which is released under an MIT Open Source license.
//
// The constants are seeded from ~1000-digit decimal literals (generated by
// tools/generators/efloat_constants_gen.py using mpmath) and converted exactly
// to binary at the requested efloat precision. This makes efloat the library's
// highest-precision constant basis: a ~3300-bit efloat<104+> reproduces these
// to ~1000 decimal digits, well beyond the ~315-digit ceiling of the
// multi-component ereal/elreal constants (issue #1139).
//
// Construction uses efloat's BigBits-templated parse() (#1141) with a large
// budget: the d2b reduction shifts the digit-integer left by ~(target +
// 3*ndigits) bits, so the budget must be well above that -- 16384 bits covers a
// 1000-digit literal at ~3300-bit target. Passing the budget explicitly does NOT
// change the shared d2b default that other number systems rely on.
#pragma once
#include <string>
#include <string_view>
#include <algorithm>

namespace sw { namespace universal {

inline constexpr const char* EFLOAT_PI_DIGITS =
    "3.";
inline constexpr const char* EFLOAT_E_DIGITS =
    "2.";
inline constexpr const char* EFLOAT_PHI_DIGITS =
    "1.";

namespace efloat_detail {

	// Largest decimal precision (in bits) the ~1000-digit literals support.
	// 1000 digits ~= 3322 bits; keep a little below to stay inside the digits.
	inline constexpr unsigned constant_literal_bits = 3300u;

	// d2b budget: the reduction shifts the digit-integer left by roughly
	// target + 3*ndigits bits, so this must sit well above both. 16384 covers a
	// 1000-digit literal at the ~3300-bit target with headroom.
	inline constexpr unsigned constant_big_bits = 16384u;

	// make_constant<nlimbs>(decimal): parse a decimal literal into an efloat at
	// min(nlimbs*32, constant_literal_bits) bits, exactly. Delegates to efloat's
	// BigBits-templated parse() (#1141): sizing the working precision first, then
	// calling parse<constant_big_bits> gives an exact conversion well past the
	// 2040-bit default d2b ceiling -- the wide budget covers the digit-integer's
	// 5^|E| growth for a ~1000-digit literal. Invalid input -> NaN.
	template<unsigned nlimbs>
	inline efloat<nlimbs> make_constant(std::string_view decimal) {
		efloat<nlimbs> value;
		const unsigned target_bits = std::min(nlimbs * 32u, constant_literal_bits);
		value.set_precision(target_bits);
		if (!parse<constant_big_bits>(std::string(decimal), value)) value.setnan();
		return value;
	}

}  // namespace efloat_detail

// efloat_pi<nlimbs>(): pi at min(nlimbs*32, ~3300) bits, cached per instantiation.
template<unsigned nlimbs>
inline efloat<nlimbs> efloat_pi() {
	static const efloat<nlimbs> c = efloat_detail::make_constant<nlimbs>(EFLOAT_PI_DIGITS);
	return c;
}

// efloat_e<nlimbs>(): Euler's number e.
template<unsigned nlimbs>
inline efloat<nlimbs> efloat_e() {
	static const efloat<nlimbs> c = efloat_detail::make_constant<nlimbs>(EFLOAT_E_DIGITS);
	return c;
}

// efloat_phi<nlimbs>(): the golden ratio phi = (1 + sqrt(5))/2.
template<unsigned nlimbs>
inline efloat<nlimbs> efloat_phi() {
	static const efloat<nlimbs> c = efloat_detail::make_constant<nlimbs>(EFLOAT_PHI_DIGITS);
	return c;
}

}} // namespace sw::universal
